    render(
      <TaskDetailHeader {...defaultProps} setIsHeaderMenuOpen={setMenu} />,
    );
    await userEvent.click(screen.getByLabelText("Rohkem valikuid"));
    expect(setMenu).toHaveBeenCalledWith(true);
